源代码：#include &lt;stdlib.h&gt;#include &lt;stdio.h&gt;#include &lt;pthread.h&gt;#define FLAG_LEN 20void * checking(void *arg) &#123;    char *result = malloc(sizeof(char));    char *argument = (char *)arg;    *result = (argument[0]+argument[1]) ^ argument[2];    return result;&#125;int highly_optimized_parallel_comparsion(char *user_string)&#123;    int initialization_number;    int i;    char generated_string[FLAG_LEN + 1];    generated_string[FLAG_LEN] = &#x27;\0&#x27;;    while ((initialization_number = rand()) &gt;= 64);    int first_letter;    first_letter = (initialization_number % 26) + 97;        //经过调试发现是固定值  112    pthread_t thread[FLAG_LEN];    char differences[FLAG_LEN] = &#123;0, 9, -9, -1, 13, -13, -4, -11, -9, -1, -7, 6, -13, 13, 3, 9, -13, -11, 6, -7&#125;;    char *arguments[20];    for (i = 0; i &lt; FLAG_LEN; i++) &#123;        arguments[i] = (char *)malloc(3*sizeof(char));        arguments[i][0] = first_letter;        arguments[i][1] = differences[i];        arguments[i][2] = user_string[i];        pthread_create((pthread_t*)(thread+i), NULL, checking, arguments[i]);    &#125;    void *result;    int just_a_string[FLAG_LEN] = &#123;115, 116, 114, 97, 110, 103, 101, 95, 115, 116, 114, 105, 110, 103, 95, 105, 116, 95, 105, 115&#125;;    for (i = 0; i &lt; FLAG_LEN; i++) &#123;        pthread_join(*(thread+i), &amp;result);        generated_string[i] = *(char *)result + just_a_string[i];        free(result);        free(arguments[i]);    &#125;    int is_ok = 1;    for (i = 0; i &lt; FLAG_LEN; i++) &#123;        if (generated_string[i] != just_a_string[i])            return 0;    &#125;    return 1;&#125;int main()&#123;    char *user_string = (char *)calloc(FLAG_LEN+1, sizeof(char));    fgets(user_string, FLAG_LEN+1, stdin);                                   //输入20个字符    int is_ok = highly_optimized_parallel_comparsion(user_string);    if (is_ok)        printf(&quot;You win!\n&quot;);    else        printf(&quot;Wrong!\n&quot;);    return 0;&#125;`````粗略看一遍,发现 ```pthread_t``` 以及```pthread_join``` ```pthread_create```函数看不懂，于是网上查资料,得知##### pthread_t``` ctypedef unsigned __int64 uintptr_ttypedef uintptr_t pthread_t;    
pthread_create    ：作用为创建新线程，如果创建成功则返回0，否则返回error numberint pthread_create(pthread_t *thread, const pthread_attr_t *attr,void *(*start_routine)(void*), void *arg);

pthread_t *thread 是线程的标识符       

pthread_attr_t *attr用来设置线程属性（如果为NULL，则为默认属性}

void *(*start_routine)(void*)  是运行函数的起始地址

void *arg运行函数的参数


prhread_join : 作用为等待一个线程的结束，如果成功则返回0，否则返回error numberint pthread_join(pthread_t thread, void **value_ptr);

pthread_t thread线程标识符

void **value_ptr 存储被等待线程的返回值


